const fs = require('fs');
const data = JSON.parse(fs.readFileSync('src/data/tebakhewan.json','utf8'));
console.log('Total hewan:', data.length);
// Check for duplicates
const jawabans = data.map(d=>d.jawaban);
const dupes = jawabans.filter((j,i)=>jawabans.indexOf(j)!==i);
if(dupes.length) console.log('DUPLIKAT:', dupes);
else console.log('Tidak ada duplikat jawaban ✅');
// Check all have img+soal+jawaban
const missing = data.filter(d=>!d.img||!d.soal||!d.jawaban);
console.log('Data tidak lengkap:', missing.length===0?'Tidak ada ✅':missing.map(d=>d.jawaban));
// Check all imgs are inaturalist
const nonInat = data.filter(d=>!d.img.includes('inaturalist'));
console.log('Non-iNaturalist:', nonInat.length===0?'Tidak ada ✅':nonInat.map(d=>d.jawaban));
" 2>/dev/null

