import { getRandomItem, createSession, getSession, endSession, checkAnswerAdvanced, getHint, hasActiveSession, setSessionTimer, getRemainingTime, isSurrender, getProgressiveHint } from './src/lib/ourin-game-data.js'

const GAME = 'tebakhewan'
const CHAT = 'simulasi@test'

console.log('=== SIMULASI TEBAKHEWAN ===\n')

