check('img adalah URL iNaturalist', item?.img?.includes('inaturalist'))
check('jawaban tidak kosong', item?.jawaban?.length > 0)
check('soal tidak kosong', item?.soal?.length > 10)

// 2. Simulasi 10 item random — cek tidak ada field yang kosong
console.log('\n--- Sampling 10 item random ---')
for (let i = 0; i < 10; i++) {
  const q = getRandomItem(GAME + '.json')
  const ok = q?.img && q?.soal && q?.jawaban && q?.img.includes('inaturalist')
  check(`Sample ${i+1}: ${q?.jawaban}`, ok)
}

// 3. Simulasi session lifecycle
console.log('\n--- Simulasi Session ---')
