const sess = getSession(CHAT)
check('Sesi punya gameType benar', sess?.gameType === GAME)
check('Sesi punya question', !!sess?.question?.jawaban)

// 4. Simulasi jawaban
console.log('\n--- Simulasi Jawaban ---')
const jawaban = sess.question.jawaban
const r1 = checkAnswerAdvanced(jawaban, jawaban)
check('Jawaban tepat → correct', r1.status === 'correct')
const r2 = checkAnswerAdvanced(jawaban, 'xyzabc123')
check('Jawaban salah → salah/close', r2.status !== 'correct')
const hint = getHint(jawaban, 2)
check('Hint tidak kosong', hint?.length > 0)
check('Hint masking jawaban', !hint?.toLowerCase().includes(jawaban.toLowerCase()))

// 5. Simulasi isSurrender
check('nyerah dikenali', isSurrender('nyerah'))
check('give up dikenali', isSurrender('give up'))
check('jawaban normal bukan surrender', !isSurrender(jawaban))

// 6. Test progressive hint
console.log('\n--- Progressive Hint ---')
for (let attempt = 1; attempt <= 5; attempt++) {
  const h = getProgressiveHint(jawaban, attempt)
  check(`Hint attempt ${attempt}: "${h}"`, h?.length > 0)
}

endSession(CHAT)
check('Sesi berhasil dihapus', !hasActiveSession(CHAT))

// 7. Cek semua 120 data valid
console.log('\n--- Validasi Semua Data ---')
import { readFileSync } from 'fs'
const allData = JSON.parse(readFileSync('src/data/tebakhewan.json', 'utf8'))
check('Total data >= 120', allData.length >= 120)
const invalid = allData.filter(d => !d.img || !d.soal || !d.jawaban || !d.img.includes('inaturalist'))
check('Semua item lengkap & valid', invalid.length === 0, invalid.map(d=>d.jawaban).join(', '))
const dupes = allData.map(d=>d.jawaban).filter((j,i,a)=>a.indexOf(j)!==i)
check('Tidak ada duplikat jawaban', dupes.length === 0, dupes.join(', '))
