check('Semua soal cukup panjang (>20 karakter)', shortSoal.length === 0, shortSoal.map(d=>d.jawaban).join(', '))

console.log(`\n${'='.repeat(35)}`)
console.log(`HASIL: ${passed} passed, ${failed} failed`)
