node --input-type=module << 'EOF'
import { getRandomItem, createSession, getSession, endSession, checkAnswerAdvanced, getHint, hasActiveSession, isSurrender, getProgressiveHint } from './src/lib/ourin-game-data.js'
import { readFileSync } from 'fs'

const GAME = 'tebakmakanan'
let passed=0, failed=0
function check(label, ok, detail='') {
  if(ok) passed++;
  else { failed++; console.log('❌', label, detail); }
}

const all = JSON.parse(readFileSync('src/data/tebakmakanan.json','utf8'))
check('Total 100 makanan', all.length === 100)
check('Semua ada img', all.every(d=>d.img))
check('Semua ada soal', all.every(d=>d.soal))
check('Semua ada jawaban', all.every(d=>d.jawaban))
check('Soal semua >20 char', all.every(d=>d.soal.length>20))
const dupes = all.map(d=>d.jawaban).filter((j,i,a)=>a.indexOf(j)!==i)
check('Zero duplikat', dupes.length===0, dupes.join(','))

// Count by source
const wiki = all.filter(d=>d.img.includes('wikimedia')).length
const mealdb = all.filter(d=>d.img.includes('themealdb')).length
console.log('Sumber: Wikipedia Commons =', wiki, '| TheMealDB =', mealdb)

// Session & gameplay simulation x5
for (let i=0; i<5; i++) {
  const chatId = 'food_'+i
  const q = getRandomItem(GAME+'.json')
  createSession(chatId, GAME, q, {id:'k'+i}, 60000)
  const sess = getSession(chatId)
  check('Sesi '+i+': '+q.jawaban, sess?.gameType===GAME && sess?.question?.jawaban===q.jawaban)
  const r = checkAnswerAdvanced(q.jawaban, q.jawaban)
  check('Jawaban benar '+i, r.status==='correct')
  const hint = getHint(q.jawaban, 2)
  check('Hint valid '+i, hint?.length>0)
  endSession(chatId)
  check('Sesi dihapus '+i, !hasActiveSession(chatId))
}
check('nyerah dikenali', isSurrender('nyerah'))
check('Jawaban bukan surrender', !isSurrender('nasi goreng'))

console.log('\n=== SIMULASI: '+passed+' passed, '+failed+' failed ===')
console.log(failed===0 ? '🟢 ZERO BUG!' : '🔴 ADA BUG!')
EOF

